        this.fRec11[1] = this.fRec11[0];
        this.fRec6[1] = this.fRec6[0];
        this.fRec0[1] = this.fRec0[0];

        if (Mathf.abs(output) < 0.00001) {
            this.silentSamples++;
        } else {
            this.silentSamples = 0;
        }

        this.channel.signal.addMonoSignal(output, 0.5, 0.5);
    }
}

